     9→ENTRY(_start)
    10→SEARCH_DIR("/local/sqa/Jenkins/workspace/build-system-3/toolchain/nds64le-elf-mculib-v5d/riscv64-elf/lib");
    11→SECTIONS
    12→{
    13→  /* Read-only sections, merged into text segment: */
    14→  PROVIDE (__executable_start = SEGMENT_START("text-segment", 0x10000)); . = SEGMENT_START("text-segment", 0x10000) + SIZEOF_HEADERS;
    15→  .interp         : { *(.interp) }
    16→  .note.gnu.build-id  : { *(.note.gnu.build-id) }
    17→  .hash           : { *(.hash) }
    18→  .gnu.hash       : { *(.gnu.hash) }
    19→  .dynsym         : { *(.dynsym) }
    20→  .dynstr         : { *(.dynstr) }
    21→  .gnu.version    : { *(.gnu.version) }
    22→  .gnu.version_d  : { *(.gnu.version_d) }
    23→  .gnu.version_r  : { *(.gnu.version_r) }
    24→  .rela.dyn       :
    25→    {
    26→      *(.rela.init)
    27→      *(.rela.text .rela.text.* .rela.gnu.linkonce.t.*)
    28→      *(.rela.fini)
    29→      *(.rela.rodata .rela.rodata.* .rela.gnu.linkonce.r.*)
    30→      *(.rela.data .rela.data.* .rela.gnu.linkonce.d.*)
    31→      *(.rela.tdata .rela.tdata.* .rela.gnu.linkonce.td.*)
    32→      *(.rela.tbss .rela.tbss.* .rela.gnu.linkonce.tb.*)
    33→      *(.rela.ctors)
    34→      *(.rela.dtors)
    35→      *(.rela.got)
    36→      *(.rela.sdata .rela.sdata.* .rela.gnu.linkonce.s.*)
    37→      *(.rela.sbss .rela.sbss.* .rela.gnu.linkonce.sb.*)
    38→      *(.rela.sdata2 .rela.sdata2.* .rela.gnu.linkonce.s2.*)
    39→      *(.rela.sbss2 .rela.sbss2.* .rela.gnu.linkonce.sb2.*)
    40→      *(.rela.bss .rela.bss.* .rela.gnu.linkonce.b.*)
    41→      PROVIDE_HIDDEN (__rela_iplt_start = .);
    42→      *(.rela.iplt)
    43→      PROVIDE_HIDDEN (__rela_iplt_end = .);
    44→    }
    45→  .rela.plt       :
    46→    {
    47→      *(.rela.plt)
    48→    }
    49→  .init           :
    50→  {
    51→    KEEP (*(SORT_NONE(.init)))
    52→  }
    53→  .plt            : { *(.plt) }
    54→  .iplt           : { *(.iplt) }
    55→  .text           :
    56→  {
    57→    *(.text.unlikely .text.*_unlikely .text.unlikely.*)
    58→    *(.text.exit .text.exit.*)
    59→    *(.text.startup .text.startup.*)
    60→    *(.text.hot .text.hot.*)
    61→    *(.text .stub .text.* .gnu.linkonce.t.*)
    62→    /* .gnu.warning sections are handled specially by elf32.em.  */
    63→    *(.gnu.warning)
    64→  }
    65→  .fini           :
    66→  {
    67→    KEEP (*(SORT_NONE(.fini)))
    68→  }
    69→  PROVIDE (__etext = .);
    70→  PROVIDE (_etext = .);
    71→  PROVIDE (etext = .);
    72→  .rodata         : { *(.rodata .rodata.* .gnu.linkonce.r.*) }
    73→  .rodata1        : { *(.rodata1) }
    74→  .sdata2         :
    75→  {
    76→    *(.sdata2 .sdata2.* .gnu.linkonce.s2.*)
    77→  }
    78→  .sbss2          : { *(.sbss2 .sbss2.* .gnu.linkonce.sb2.*) }
    79→  .eh_frame_hdr   : { *(.eh_frame_hdr) *(.eh_frame_entry .eh_frame_entry.*) }
    80→  .eh_frame       : ONLY_IF_RO { KEEP (*(.eh_frame)) *(.eh_frame.*) }
    81→  .gcc_except_table   : ONLY_IF_RO { *(.gcc_except_table .gcc_except_table.*) }
    82→  .gnu_extab   : ONLY_IF_RO { *(.gnu_extab*) }
    83→  /* These sections are generated by the Sun/Oracle C++ compiler.  */
    84→  .exception_ranges   : ONLY_IF_RO { *(.exception_ranges*) }
    85→  /* Adjust the address for the data segment.  We want to adjust up to
    86→     the same address within the page on the next page up.  */
    87→  . = DATA_SEGMENT_ALIGN (CONSTANT (MAXPAGESIZE), CONSTANT (COMMONPAGESIZE));
    88→  /* Exception handling  */
    89→  .eh_frame       : ONLY_IF_RW { KEEP (*(.eh_frame)) *(.eh_frame.*) }
    90→  .gnu_extab      : ONLY_IF_RW { *(.gnu_extab) }
    91→  .gcc_except_table   : ONLY_IF_RW { *(.gcc_except_table .gcc_except_table.*) }
    92→  .exception_ranges   : ONLY_IF_RW { *(.exception_ranges*) }
    93→  /* Thread Local Storage sections  */
    94→  .tdata          :
    95→   {
    96→     PROVIDE_HIDDEN (__tdata_start = .);
    97→     *(.tdata .tdata.* .gnu.linkonce.td.*)
    98→   }
    99→  .tbss           : { *(.tbss .tbss.* .gnu.linkonce.tb.*) *(.tcommon) }
   100→  .preinit_array    :
   101→  {
   102→    PROVIDE_HIDDEN (__preinit_array_start = .);
   103→    KEEP (*(.preinit_array))
   104→    PROVIDE_HIDDEN (__preinit_array_end = .);
   105→  }
   106→  .init_array    :
   107→  {
   108→    PROVIDE_HIDDEN (__init_array_start = .);
   109→    KEEP (*(SORT_BY_INIT_PRIORITY(.init_array.*) SORT_BY_INIT_PRIORITY(.ctors.*)))
   110→    KEEP (*(.init_array EXCLUDE_FILE (*crtbegin.o *crtbegin?.o *crtend.o *crtend?.o ) .ctors))
   111→    PROVIDE_HIDDEN (__init_array_end = .);
   112→  }
   113→  .fini_array    :
   114→  {
   115→    PROVIDE_HIDDEN (__fini_array_start = .);
   116→    KEEP (*(SORT_BY_INIT_PRIORITY(.fini_array.*) SORT_BY_INIT_PRIORITY(.dtors.*)))
   117→    KEEP (*(.fini_array EXCLUDE_FILE (*crtbegin.o *crtbegin?.o *crtend.o *crtend?.o ) .dtors))
   118→    PROVIDE_HIDDEN (__fini_array_end = .);
   119→  }
   120→  .ctors          :
   121→  {
   122→    /* gcc uses crtbegin.o to find the start of
   123→       the constructors, so we make sure it is
   124→       first.  Because this is a wildcard, it
   125→       doesn't matter if the user does not
   126→       actually link against crtbegin.o; the
   127→       linker won't look for a file to match a
   128→       wildcard.  The wildcard also means that it
   129→       doesn't matter which directory crtbegin.o
   130→       is in.  */
   131→    KEEP (*crtbegin.o(.ctors))
   132→    KEEP (*crtbegin?.o(.ctors))
   133→    /* We don't want to include the .ctor section from
   134→       the crtend.o file until after the sorted ctors.
   135→       The .ctor section from the crtend file contains the
   136→       end of ctors marker and it must be last */
   137→    KEEP (*(EXCLUDE_FILE (*crtend.o *crtend?.o ) .ctors))
   138→    KEEP (*(SORT(.ctors.*)))
   139→    KEEP (*(.ctors))
   140→  }
   141→  .dtors          :
   142→  {
   143→    KEEP (*crtbegin.o(.dtors))
   144→    KEEP (*crtbegin?.o(.dtors))
   145→    KEEP (*(EXCLUDE_FILE (*crtend.o *crtend?.o ) .dtors))
   146→    KEEP (*(SORT(.dtors.*)))
   147→    KEEP (*(.dtors))
   148→  }
   149→  .jcr            : { KEEP (*(.jcr)) }
   150→  .data.rel.ro : { *(.data.rel.ro.local* .gnu.linkonce.d.rel.ro.local.*) *(.data.rel.ro .data.rel.ro.* .gnu.linkonce.d.rel.ro.*) }
   151→  .dynamic        : { *(.dynamic) }
   152→  . = DATA_SEGMENT_RELRO_END (0, .);
   153→  .data           :
   154→  {
   155→    __DATA_BEGIN__ = .;
   156→    *(.data .data.* .gnu.linkonce.d.*)
   157→    SORT(CONSTRUCTORS)
   158→  }
   159→  .data1          : { *(.data1) }
   160→  .got            : { *(.got.plt) *(.igot.plt) *(.got) *(.igot) }
   161→  /* We want the small data sections together, so single-instruction offsets
   162→     can access them all, and initialized data all before uninitialized, so
   163→     we can shorten the on-disk segment size.  */
   164→  .sdata          :
   165→  {
   166→    . = ALIGN (64 / 8);
   167→    __SDATA_BEGIN__ = .;
   168→    __global_pointer$ = __SDATA_BEGIN__ + 0x800;
   169→    *(.srodata.cst16) *(.srodata.cst8) *(.srodata.cst4) *(.srodata.cst2) *(.srodata .srodata.*)
   170→    *(.sdata .sdata.* .gnu.linkonce.s.*)
   171→  }
   172→  _edata = .; PROVIDE (edata = .);
   173→  . = .;
   174→  __bss_start = .;
   175→  .sbss           :
   176→  {
   177→    *(.dynsbss)
   178→    *(.sbss .sbss.* .gnu.linkonce.sb.*)
   179→    *(.scommon)
   180→  }
   181→  .bss            :
   182→  {
   183→   *(.dynbss)
   184→   *(.bss .bss.* .gnu.linkonce.b.*)
   185→   *(COMMON)
   186→   /* Align here to ensure that the .bss section occupies space up to
   187→      _end.  Align after .bss to ensure correct alignment even if the
   188→      .bss section disappears because there are no input sections.
   189→      FIXME: Why do we need it? When there is no .bss section, we do not
   190→      pad the .data section.  */
   191→   . = ALIGN(. != 0 ? 64 / 8 : 1);
   192→  }
   193→  . = ALIGN(64 / 8);
   194→  . = SEGMENT_START("ldata-segment", .);
   195→  . = ALIGN(64 / 8);
   196→  __BSS_END__ = .;
   197→  /* PROVIDE (_stack = 0x3000000); */
   198→  PROVIDE (_stack = ALIGN(__BSS_END__ + 0x10000000, 16));
   199→  _end = .; PROVIDE (end = .);
   200→  /* PROVIDE (_stack = _end + 0x010000000); */
   201→  . = DATA_SEGMENT_END (.);
   202→  /* Stabs debugging sections.  */
   203→  .stab          0 : { *(.stab) }
   204→  .stabstr       0 : { *(.stabstr) }
   205→  .stab.excl     0 : { *(.stab.excl) }
   206→  .stab.exclstr  0 : { *(.stab.exclstr) }
   207→  .stab.index    0 : { *(.stab.index) }
   208→  .stab.indexstr 0 : { *(.stab.indexstr) }
   209→  .comment       0 : { *(.comment) }
   210→  .gnu.build.attributes : { *(.gnu.build.attributes .gnu.build.attributes.*) }
   211→  /* DWARF debug sections.
   212→     Symbols in the DWARF debugging sections are relative to the beginning
   213→     of the section so we begin them at 0.  */
   214→  /* DWARF 1 */
   215→  .debug          0 : { *(.debug) }
   216→  .line           0 : { *(.line) }
   217→  /* GNU DWARF 1 extensions */
   218→  .debug_srcinfo  0 : { *(.debug_srcinfo) }
   219→  .debug_sfnames  0 : { *(.debug_sfnames) }
   220→  /* DWARF 1.1 and DWARF 2 */
   221→  .debug_aranges  0 : { *(.debug_aranges) }
   222→  .debug_pubnames 0 : { *(.debug_pubnames) }
   223→  /* DWARF 2 */
   224→  .debug_info     0 : { *(.debug_info .gnu.linkonce.wi.*) }
   225→  .debug_abbrev   0 : { *(.debug_abbrev) }
   226→  .debug_line     0 : { *(.debug_line .debug_line.* .debug_line_end) }
   227→  .debug_frame    0 : { *(.debug_frame) }
   228→  .debug_str      0 : { *(.debug_str) }
   229→  .debug_loc      0 : { *(.debug_loc) }
   230→  .debug_macinfo  0 : { *(.debug_macinfo) }
   231→  /* SGI/MIPS DWARF 2 extensions */
   232→  .debug_weaknames 0 : { *(.debug_weaknames) }
   233→  .debug_funcnames 0 : { *(.debug_funcnames) }
   234→  .debug_typenames 0 : { *(.debug_typenames) }
   235→  .debug_varnames  0 : { *(.debug_varnames) }
   236→  /* DWARF 3 */
   237→  .debug_pubtypes 0 : { *(.debug_pubtypes) }
   238→  .debug_ranges   0 : { *(.debug_ranges) }
   239→  /* DWARF Extension.  */
   240→  .debug_macro    0 : { *(.debug_macro) }
   241→  .debug_addr     0 : { *(.debug_addr) }
   242→  .gnu.attributes 0 : { KEEP (*(.gnu.attributes)) }
   243→  /DISCARD/ : { *(.note.GNU-stack) *(.gnu_debuglink) *(.gnu.lto_*) }
   244→}
