    48→// A function to create the HAL device from the different backend targets.
    49→// The HAL device is returned based on the implementation, and it must be
    50→// released by the caller.
    51→iree_status_t create_device_with_static_loader(iree_allocator_t host_allocator,
    52→                                               iree_hal_device_t** out_device) {
    53→  // Set paramters for the device created in the next step.
    54→  iree_hal_sync_device_params_t params;
    55→  iree_hal_sync_device_params_initialize(&params);
    56→
    57→  // Register the statically linked executable library.
    58→  const iree_hal_executable_library_query_fn_t libraries[] = {
    59→      QUERY,
    60→  };
    61→  iree_hal_executable_loader_t* library_loader = NULL;
    62→  iree_status_t status = iree_hal_static_library_loader_create(
    63→      IREE_ARRAYSIZE(libraries), libraries,
    64→      iree_hal_executable_import_provider_null(), host_allocator,
    65→      &library_loader);
    66→
    67→  // Use the default host allocator for buffer allocations.
    68→  iree_string_view_t identifier = iree_make_cstring_view("local-sync");
    69→  iree_hal_allocator_t* device_allocator = NULL;
    70→  if (iree_status_is_ok(status)) {
    71→    status = iree_hal_allocator_create_heap(identifier, host_allocator,
    72→                                            host_allocator, &device_allocator);
    73→  }
    74→
    75→  // Create the device and release the executor and loader afterwards.
    76→  if (iree_status_is_ok(status)) {
    77→    status = iree_hal_sync_device_create(
    78→        identifier, &params, /*loader_count=*/1, &library_loader,
    79→        device_allocator, host_allocator, out_device);
    80→  }
    81→
    82→  iree_hal_allocator_release(device_allocator);
    83→  iree_hal_executable_loader_release(library_loader);
    84→  return status;
    85→}
